@@ -0,0 +1,14 @@
+{
+  "name": "full_reset_clears_decom",
+  "description": "Full reset (ESC c) clears scroll region, DECOM, and all modes; cursor returns to (0,0)",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b323b34721b5b3f36681b5b48411b6342",
+  "comment": "Set scroll region 2-4, DECOM on, CUP → region top (1,0), print A, ESC c full reset clears everything, print B at (0,0); cursor at (0,1)",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "B" },
+      { "row": 1, "col": 0, "char": " " }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "decom_cup_relative",
+  "description": "DECOM (origin mode) makes CUP addressing relative to scroll region",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b323b34721b5b3f36681b5b48411b5b323b314842",
+  "comment": "CSI 2;4 r (region rows 1-3), CSI ? 6 h (DECOM on), CUP(H) → top of region (1,0), print A, CUP(2,1) → region-relative row 2 = abs row 2 col 0, print B; cursor at (2,1)",
+  "expected": {
+    "cursor": { "row": 2, "col": 1 },
+    "cells": [
+      { "row": 1, "col": 0, "char": "A" },
+      { "row": 2, "col": 0, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "decom_save_restore",
+  "description": "Save/restore cursor preserves position with DECOM; turning DECOM off uses absolute addressing",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b323b34721b5b3f36681b5b48581b371b5b3f366c1b5b48591b385a",
+  "comment": "CSI 2;4 r (region rows 1-3), DECOM on, CUP(H) → (1,0), print X at (1,0) cursor at (1,1), ESC 7 save, DECOM off, CUP(H) → (0,0) absolute, print Y at (0,0), ESC 8 restore → (1,1), print Z at (1,1); cursor at (1,2)",
+  "expected": {
+    "cursor": { "row": 1, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "Y" },
+      { "row": 1, "col": 0, "char": "X" },
+      { "row": 1, "col": 1, "char": "Z" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "custom_tab_stops",
+  "description": "Clear all default tab stops, set custom stops at cols 4 and 9, tab through them",
+  "initial_size": [20, 3],
+  "input_bytes_hex": "1b5b33671b5b35471b481b5b3130471b481b5b484109420943",
+  "comment": "CSI 3 g (clear all tabs), CUP col 5 → col 4, HTS set tab, CUP col 10 → col 9, HTS set tab, CUP home, print A at col 0, TAB → col 4, print B at col 4, TAB → col 9, print C at col 9; cursor at (0,10)",
+  "expected": {
+    "cursor": { "row": 0, "col": 10 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 4, "char": "B" },
+      { "row": 0, "col": 9, "char": "C" }
+    ]
+  }
+}
